/* ─── UK Template filler ─────────────────────────────────────── */
function f(t, v) {
  if (typeof t !== 'string') return t;
  return t.replace(/\{(\w+)\}/g, (_, k) => v[k] ?? '');
}
function fd(o, v) {
  if (typeof o === 'string') return f(o, v);
  if (Array.isArray(o)) return o.map(i => fd(i, v));
  if (o && typeof o === 'object') {
    const r = {};
    for (const [k, val] of Object.entries(o)) r[k] = fd(val, v);
    return r;
  }
  return o;
}

