/* ─── buildUKContent ─────────────────────────────────────────── */
export function buildUKContent(serviceSlug, regionData) {
  const config = UK_CONFIGS[serviceSlug];
  if (!config) return null;

  const cities = regionData.cities || [];
  const vars = {
    state:  regionData.state,
    city1:  cities[0]?.city || regionData.state,
    city2:  cities[1]?.city || cities[0]?.city || regionData.state,
    city3:  cities[2]?.city || cities[1]?.city || cities[0]?.city || regionData.state,
    abbr:   regionData.stateAbbr || 'UK',
  };

  const result = fd(config, vars);

  // Assign H1 hook
  const h1Pool = getUKH1Hooks(serviceSlug, regionData);
  const variant = (regionData.state.charCodeAt(0) + serviceSlug.charCodeAt(0)) % Math.max(h1Pool.length, 1);
  result.heroH1 = h1Pool[variant] || null;

  return result;
}

export default UK_CONFIGS;
